import countryRegistryData from "./generated/countryRegistry.json" with { type: "json" };

/**
 * Scalable country registry seam (Step 1 of the global data/image
 * expansion plan - see docs/GLOBAL_DATA_AND_IMAGE_EXPANSION_PLAN.md).
 * Regenerated by scripts/ingestion/buildCountryRegistry.mjs; every module
 * that needs "which countries exist / do we have data for this one" reads
 * through here, never the raw generated JSON directly.
 */
export const countryRegistry = countryRegistryData.countries ?? [];

export const enabledCountries = countryRegistry.filter((country) => country.enabled);
export const activeCountries = countryRegistry.filter((country) => country.dataStatus === "active");

function normalizeName(name) {
  return (name || "").trim().toLowerCase();
}

const byIso2 = new Map(countryRegistry.filter((c) => c.iso2).map((c) => [c.iso2.toUpperCase(), c]));
const byNormalizedName = new Map(countryRegistry.map((c) => [normalizeName(c.countryName), c]));

export function getCountryRegistryEntry({ iso2, countryName } = {}) {
  if (iso2 && byIso2.has(iso2.toUpperCase())) return byIso2.get(iso2.toUpperCase());
  if (countryName && byNormalizedName.has(normalizeName(countryName))) return byNormalizedName.get(normalizeName(countryName));
  return null;
}

// A country with no research records yet still deserves an honest,
// specific message rather than an empty section - this is that message,
// in one place so every page using the registry says it the same way.
export function getNoDataMessage(entry) {
  if (!entry) return "No research records found yet.";
  if (entry.dataStatus === "no-data") return "No research records found yet - pending data discovery.";
  if (entry.dataStatus === "pending") return "Country identified, but no source-verified research records yet.";
  return "No research records found yet.";
}

export const countryRegistryMeta = {
  generatedAt: countryRegistryData.generatedAt,
  totalCountries: countryRegistryData.totalCountries,
  enabledCountries: countryRegistryData.enabledCountries,
  activeCountries: countryRegistryData.activeCountries,
};
